class Circle {
  constructor(radius) {
    this.radius = radius;
  }
  get area() {
    return Math.PI * this.radius ** 2;
  }
  set radius(r) {
    this._radius = r < 0 ? 0 : r;
  }
  get radius() {
    return this._radius;
  }
}
const c = new Circle(2);
console.log(c.area.toFixed(2));
c.radius = -5;
console.log(c.radius);

